defmodule WebHookProxyController do
    use Phoenix.Controller, namespace: :web_hooks
    
    plug Uri.Parser when into: [:request] # Parse the URI from request params and put it in `assigns` map for consumption by controller actions 
  
    def get(conn, %{"url" => url}) do
        {status, response} = HTTPoison.get("#{url}/api/content")    
        
       # Prevent server-side request forgery (SSRF) here if needed... not required for this example 
  
        conn
        |> put_resp_header("content-type", "application/json; charset=utf-8")   
        |> send_resp(status, response)     # Send HTTP status and content back to client.      
      end        
end